func TestNewRepository(t *testing.T) {
    t.Parallel()
    conn, _ := db.TestSetup(t, "postgres")
    rw := db.New(conn)
    wrapper := db.TestWrapper(t)
    testKms := kms.TestKms(t, conn, wrapper)
    type args struct {
        r   db.Reader
        w   db.Writer
        kms *kms.Kms
    }
    tests := []struct {
        name          string
        args          args
        want          *Repository
        wantErr       bool
        wantErrString string
    }{
        {
            name: "valid",
            args: args{
                r:   rw,
                w:   rw,
                kms: testKms,
            },
            want: &Repository{
                reader:       rw,
                writer:       rw,
                kms:          testKms,
                defaultLimit: db.DefaultLimit,
            },
            wantErr: false,
        },
        {
            name: "nil-kms",
            args: args{
                r:   rw,
                w:   rw,
                kms: nil,
            },
            want:          nil,
            wantErr:       true,
            wantErrString: "iam.NewRepository: nil kms: parameter violation: error #100",
        },
        {
            name: "nil-writer",
            args: args{
                r:   rw,
                w:   nil,
                kms: testKms,
            },
            want:          nil,
            wantErr:       true,
            wantErrString: "iam.NewRepository: nil writer: parameter violation: error #100",
        },
        {
            name: "nil-reader",
            args: args{
                r:   nil,
                w:   rw,
                kms: testKms,
            },
            want:          nil,
            wantErr:       true,
            wantErrString: "iam.NewRepository: nil reader: parameter violation: error #100",
        },
    }
    for _, tt := range tests {
        tt.Run(tt.name, func(t *testing.T) {
            assert, require := assert.New(t), require.New(t)
            got, err := NewRepository(context.Background(), tt.args.r, tt.args.w, tt.args.kms)
            if tt.wantErr {
                require.Error(err)
                assert.Equal(tt.wantErrString, err.Error())
                return
            }
            require.NoError(err)
            assert.Equal(tt.want, got)
        })
    }
}

